// ✏️ PASTE YOUR APIFY DATASET ID HERE after each manual run
const datasetId = 'WOesH2E4XuaWmVYdN';

// ✏️ Describe what you searched for (for the summary email)
// e.g. 'Property Management Companies | Jacksonville FL'
const searchDescription = 'HOA / Community Managers | Jacksonville FL';

return [{ json: { datasetId, searchDescription } }];

const allItems = $input.all();
const searchDescription = $('Set Dataset ID').first().json.searchDescription;
const datasetId = $('Set Dataset ID').first().json.datasetId;

const rawLeads = allItems.map(item => item.json);

if (!rawLeads || rawLeads.length === 0) {
  console.log('No items found in dataset.');
  return [{ json: {
    _empty: true,
    searchDescription,
    datasetId,
    _stats: { total_raw: 0, valid: 0, skipped: 0, skip_reasons: {} }
  }}];
}

const leads = [];
const skipped = [];
const seenPhones = new Set();
const seenEmails = new Set();
const seenDomains = new Set();
const skipReasons = {};

const trackSkip = (name, reason) => {
  skipped.push({ name, reason });
  skipReasons[reason] = (skipReasons[reason] || 0) + 1;
};

// Helper: normalize state abbreviation
const normalizeState = (s) => {
  if (!s) return 'FL';
  const lower = s.toLowerCase().trim();
  if (lower === 'florida') return 'FL';
  return s.trim().toUpperCase();
};

for (const item of rawLeads) {
  const businessName = item.title || item.name || item.business_name || 'N/A';
  const phone = item.phone || item.phoneNumber || item.phone_number || null;
  const email = item.email || item.business_email || null;

  // FIX: Only use item.website for domain — never fall back to item.url
  // item.url is a Google Maps URL and would poison domain dedup with google.com
  const rawWebsite = item.website || '';
  const websiteDomain = rawWebsite
    ? rawWebsite.replace(/^https?:\/\/(www\.)?/, '').replace(/\/.*$/, '').toLowerCase().trim()
    : null;
  const emailDomain = email ? email.split('@')[1]?.toLowerCase() : null;

  // Domain: prefer website domain, fall back to email domain — never use item.url
  const domain = item.domain || websiteDomain || emailDomain || null;
  const website = rawWebsite || null;

  const category = item.category || item.categoryName || item.type || 'N/A';
  const city = item.city || item.address?.city || 'Jacksonville';

  // FIX: Normalize state — Apify returns 'Florida', schema expects 'FL'
  const state = normalizeState(item.state || item.address?.state);

  const source = 'apify';

  // 1. Must have business name
  if (businessName === 'N/A') { trackSkip(businessName, 'No business name'); continue; }

  // 2. Must be Jacksonville
  const cityLower = city.toLowerCase();
  if (!cityLower.includes('jacksonville')) { trackSkip(businessName, `Not Jacksonville: ${city}`); continue; }

  // 3. Must have phone OR email
  if (!phone && !email) { trackSkip(businessName, 'No phone or email'); continue; }

  // 4. In-memory dedup
  const cleanPhone = phone ? phone.replace(/\D/g, '') : null;
  const cleanEmail = email ? email.toLowerCase() : null;
  const cleanDomain = domain ? domain.toLowerCase() : null;

  if (cleanPhone && seenPhones.has(cleanPhone)) { trackSkip(businessName, `Duplicate phone: ${phone}`); continue; }
  if (cleanEmail && seenEmails.has(cleanEmail)) { trackSkip(businessName, `Duplicate email: ${email}`); continue; }
  if (cleanDomain && seenDomains.has(cleanDomain)) { trackSkip(businessName, `Duplicate domain: ${domain}`); continue; }

  if (cleanPhone) seenPhones.add(cleanPhone);
  if (cleanEmail) seenEmails.add(cleanEmail);
  if (cleanDomain) seenDomains.add(cleanDomain);

  // 5. Determine status
  const status = phone ? 'new' : 'email_only';

  leads.push({
    business_name: businessName,
    category,
    phone: phone || null,
    email: email || null,
    website: website || null,
    domain: cleanDomain || null,
    city,
    state,
    source,
    status,
    _searchDescription: searchDescription,
    _datasetId: datasetId
  });
}

const stats = {
  total_raw: rawLeads.length,
  valid: leads.length,
  skipped: skipped.length,
  skip_reasons: skipReasons,
  skipped_details: skipped
};

console.log(`Raw: ${stats.total_raw} | Valid: ${stats.valid} | Skipped: ${stats.skipped}`);
console.log('Skip reasons:', JSON.stringify(skipReasons));

if (leads.length === 0) {
  return [{ json: { _empty: true, searchDescription, datasetId, _stats: stats } }];
}

// FIX: Attach _finalStats to ALL leads so it survives even if the last lead
// gets filtered out downstream
return leads.map(l => ({ json: { ...l, _finalStats: stats } }));

const allItems = $input.all();

// FIX: Supabase with 'resolution=ignore-duplicates,return=representation' returns:
//   - non-empty array  → row was newly inserted
//   - empty array []   → row already existed (duplicate ignored)
//   - non-array        → error occurred
const saved = allItems.filter(i =>
  Array.isArray(i.json) && i.json.length > 0
).length;

const supabaseDuplicates = allItems.filter(i =>
  Array.isArray(i.json) && i.json.length === 0
).length;

const failed = allItems.filter(i =>
  !Array.isArray(i.json)
).length;

const searchDescription = $('Set Dataset ID').first().json.searchDescription;
const datasetId = $('Set Dataset ID').first().json.datasetId;

// FIX: _finalStats is now on every lead, so grab from first item
let parseStats = { total_raw: 0, valid: 0, skipped: 0, skip_reasons: {}, skipped_details: [] };
try {
  const parseItems = $('Parse & Map Results').all();
  if (parseItems.length > 0 && parseItems[0].json._finalStats) {
    parseStats = parseItems[0].json._finalStats;
  }
} catch(e) {
  console.log('Could not recover parse stats:', e.message);
}

// Count phone vs email-only leads
const parseItems = $('Parse & Map Results').all();
const phoneLeads = parseItems.filter(i => i.json.phone && !i.json._empty).length;
const emailOnlyLeads = parseItems.filter(i => !i.json.phone && i.json.email && !i.json._empty).length;

const runDate = new Date().toISOString();

console.log(`Summary — Raw: ${parseStats.total_raw} | Valid: ${parseStats.valid} | Skipped: ${parseStats.skipped} | Saved: ${saved} | Duplicates: ${supabaseDuplicates} | Failed: ${failed}`);

return [{ json: {
  total_raw: parseStats.total_raw,
  total_valid: parseStats.valid,
  total_skipped: parseStats.skipped,
  skip_reasons: parseStats.skip_reasons,
  skipped_details: parseStats.skipped_details,
  total_saved: saved,
  total_duplicates: supabaseDuplicates,
  total_failed: failed,
  phone_leads: phoneLeads,
  email_only_leads: emailOnlyLeads,
  searchDescription,
  datasetId,
  run_date: runDate
}}];
